#include <bits/stdc++.h>
using namespace std;
const int N=200005;
int n,a[N],tr[N],l[N],r[N],ll[N],rr[N];
void add(int x,int y)
{
	for(int i=x;i<=N-5;i+=(i&(-i)))
	{
		tr[i]+=y;
	}
}
int sum(int x) 
{
	int cnt=0;
	for(;x;x-=(x&(-x)))
	{
		cnt+=tr[x];
	}
	return cnt;
}
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int i=1;i<=n;i++)
	{
		l[i]=i-1-sum(a[i]);
		ll[i]=sum(a[i]-1);
		add(a[i],1);
	}
	memset(tr,0,sizeof(tr));
	for(int i=n;i>0;i--)
	{
		r[i]=n-i-sum(a[i]);
		rr[i]=sum(a[i]-1);
		add(a[i],1);
	}
	int ans1=0,ans2=0;
	for(int i=1;i<=n;i++)
	{
		ans1+=(l[i]*r[i]);
		ans2+=(ll[i]*rr[i]);
	}
	cout<<ans1<<" "<<ans2;
	return 0;
}
